#include <iostream>
using namespace std;
class Shape {
public:
    virtual void draw() { cout << "Shape" << endl; }
    virtual ~Shape() {}
};
class Circle : public Shape {
public:
    void draw() override { cout << "Circle" << endl; }
};
class Rect : public Shape {
public:
    void draw() override { cout << "Rect" << endl; }
};
int main() {
    Shape* arr[3];
    arr[0] = new Shape();
    arr[1] = new Circle();
    arr[2] = new Rect();
    for(int i = 0; i < 3; i++) arr[i]->draw();
    for(int i = 0; i < 3; i++) delete arr[i];
    return 0;
}

